{"code":"import json
import re

with open(locals()['var_function-call-7732815880617685738'], 'r') as f:
    papers = json.load(f)

def get_year(text):
    snippets = [text[:3000], text[-3000:]] # Increased range
    combined = " ".join(snippets)

    conf_pattern = r"(CHI|DIS|UbiComp|CSCW|IUI|TEI|AH|OzCHI|PervasiveHealth|WWW).{0,20}('16|2016)"
    if re.search(conf_pattern, combined, re.IGNORECASE):
        return 2016

    if re.search(r"(Copyright|Permission|ACM).{0,300}2016", combined, re.DOTALL | re.IGNORECASE):
        return 2016

    if re.search(r"(Jan|Feb|Mar|Apr|May|Jun|Jul|Aug|Sep|Oct|Nov|Dec).{0,20}2016", combined, re.IGNORECASE):
        return 2016

    return None

matches = []
for paper in papers:
    if get_year(paper['text']) == 2016:
        matches.append(paper['filename'])

print("__RESULT__:")
print(json.dumps(matches))"}

